import Combine
import Foundation

/// Native implementation of HybridBenchmarkProtocol.
/// This file is yours to edit — the protocol is generated by `nitrogen generate`.
public class BenchmarkImpl: NSObject, HybridBenchmarkProtocol {

    public override init() {
        super.init()
        self.startEmitter()
    }

    private var cancellables = Set<AnyCancellable>()
    private var angle: Double = 0

    private func startEmitter() {
        // 60 FPS = 0.016s
        Timer.publish(every: 0.016, on: .main, in: .common)
            .autoconnect()
            .sink { [weak self] _ in
                guard let self = self else { return }
                self.angle += 0.05
                
                // Visual Stress Test (BenchmarkBox)
                let r = Int64((sin(self.angle) + 1.0) * 127)
                let g = Int64((sin(self.angle + 2.0) + 1.0) * 127)
                let b = Int64((sin(self.angle + 4.0) + 1.0) * 127)
                let color = 0xFF000000 | (r << 16) | (g << 8) | b
                
                let width = 100.0 + sin(self.angle * 0.5) * 50.0
                let height = 100.0 + cos(self.angle * 0.5) * 50.0
                
                self._boxSubject.send(BenchmarkBox(color: color, width: width, height: height))
                
                // Point Stress Test
                self._dataSubject.send(BenchmarkPoint(x: sin(self.angle), y: cos(self.angle)))
            }
            .store(in: &cancellables)
    }

    public func add(a: Double, b: Double) -> Double {
        return a + b
    }

    public func addFast(a: Double, b: Double) -> Double {
        return a + b
    }

    public func getGreeting(name: String) -> String {
        return "Hello, \(name)!"
    }

    public func scalePoint(point: BenchmarkPoint, factor: Double) -> BenchmarkPoint {
        return BenchmarkPoint(x: point.x * factor, y: point.y * factor)
    }

    public func computeStats(iterations: Int64) async throws -> BenchmarkStats {
        return BenchmarkStats(
            count: iterations,
            meanUs: 1.5,
            minUs: 1.2,
            maxUs: 2.5
        )
    }

    public func sendLargeBuffer(buffer: Data) -> Int64 {
        var sum: UInt8 = 0
        // Access memory to prevent optimization
        buffer.withUnsafeBytes { ptr in
            let bytes = ptr.bindMemory(to: UInt8.self)
            for i in stride(from: 0, to: buffer.count, by: 4096) {
                sum = sum &+ bytes[i]
            }
        }
        return Int64(buffer.count)
    }

    public var dataStream: AnyPublisher<BenchmarkPoint, Never> {
        return _dataSubject.eraseToAnyPublisher()
    }

    public var boxStream: AnyPublisher<BenchmarkBox, Never> {
        return _boxSubject.eraseToAnyPublisher()
    }

    private let _dataSubject = PassthroughSubject<BenchmarkPoint, Never>()
    private let _boxSubject = PassthroughSubject<BenchmarkBox, Never>()
}
